import pytest
from datetime import datetime, timezone
from models import Job, parse_posted_at


class TestParsePostedAt:
    def test_empty_returns_none(self):
        assert parse_posted_at("") is None
        assert parse_posted_at(None) is None

    def test_lever_millisecond_epoch(self):
        dt = parse_posted_at("1643241332430")
        assert dt == datetime.fromtimestamp(1643241332.430, tz=timezone.utc)

    def test_second_epoch_below_1e12_boundary(self):
        dt = parse_posted_at("999999999999")  # 12 digits, just under 1e12
        assert dt.year > 2100  # treated as seconds, not ms — documents the boundary

    def test_iso_with_z_suffix(self):
        assert parse_posted_at("2026-01-01T00:00:00Z").tzinfo is not None

    def test_iso_naive_assumes_utc(self):
        dt = parse_posted_at("2026-01-01T00:00:00")
        assert dt.tzinfo == timezone.utc

    def test_malformed_string_returns_none(self):
        assert parse_posted_at("Posted 3 Days Ago") is None

    def test_negative_epoch(self):
        assert parse_posted_at("-1") is not None


class TestJob:
    def _job(self, **kw):
        defaults = dict(source="greenhouse", company="acme", external_id="1",
                         title="Engineer", url="http://x", location="NYC",
                         department="Eng")
        return Job(**{**defaults, **kw})

    def test_key_format(self):
        assert self._job().key == "greenhouse:acme:1"

    def test_content_hash_stable_across_irrelevant_fields(self):
        a = self._job(salary_range="100k", employment_type="FT")
        b = self._job(salary_range="200k", employment_type="PT")
        assert a.content_hash == b.content_hash

    def test_content_hash_changes_on_title(self):
        a, b = self._job(), self._job(title="Senior Engineer")
        assert a.content_hash != b.content_hash

    def test_to_row_drops_raw_adds_key_and_hash(self):
        row = self._job(raw={"secret": 1}).to_row()
        assert "raw" not in row
        assert row["key"] == "greenhouse:acme:1"
        assert "content_hash" in row

    def test_posted_dt_unparseable_is_none(self):
        assert self._job(posted_at="garbage").posted_dt is None
