from datetime import datetime, timedelta, timezone
from filters import match, filter_jobs
from models import Job


def _job(title="Software Engineer", dept="Eng", loc="Remote", posted_at=""):
    return Job(source="s", company="c", external_id="1", title=title,
               url="u", location=loc, department=dept, posted_at=posted_at)


class TestMatch:
    def test_exclude_wins_over_include(self):
        j = _job(title="Senior Engineer Intern")
        assert match(j, include=["engineer"], exclude=["intern"]) is False

    def test_include_whole_word_only(self):
        j = _job(title="Engineering Manager")
        assert match(j, include=["eng"]) is False  # substring shouldn't match

    def test_case_insensitive(self):
        assert match(_job(title="ENGINEER"), include=["engineer"]) is True

    def test_special_regex_chars_escaped(self):
        j = _job(title="C++ Developer")
        assert match(j, include=["C++"]) is True

    def test_location_substring_match(self):
        assert match(_job(loc="New York City"), locations=["new york"]) is True

    def test_unparseable_posted_at_survives_cutoff(self):
        j = _job(posted_at="not-a-date")
        cutoff = datetime.now(timezone.utc) - timedelta(days=1)
        assert match(j, cutoff=cutoff) is True

    def test_old_job_dropped_by_cutoff(self):
        old = (datetime.now(timezone.utc) - timedelta(days=10)).isoformat()
        j = _job(posted_at=old)
        cutoff = datetime.now(timezone.utc) - timedelta(days=5)
        assert match(j, cutoff=cutoff) is False


class TestFilterJobs:
    def test_max_age_days_as_string_coerces(self):
        old = (datetime.now(timezone.utc) - timedelta(days=10)).isoformat()
        jobs = [_job(posted_at=old)]
        assert filter_jobs(jobs, {"max_age_days": "5"}) == []

    def test_no_rules_passes_everything(self):
        jobs = [_job()]
        assert filter_jobs(jobs, {}) == jobs
