import pytest
from store import Store
from models import Job


@pytest.fixture
def store(tmp_path):
    with Store(tmp_path / "test.db") as s:
        yield s


def _job(ext_id="1", title="Engineer", **kw):
    return Job(source="greenhouse", company="acme", external_id=ext_id,
               title=title, url="u", **kw)


class TestDiff:
    def test_new_job_reported_and_persisted(self, store):
        new, changed = store.diff([_job()])
        assert len(new) == 1 and changed == []
        assert store.count() == 1

    def test_unchanged_job_not_reported(self, store):
        store.diff([_job()])
        new, changed = store.diff([_job()])
        assert new == [] and changed == []

    def test_changed_content_reported(self, store):
        store.diff([_job(title="Engineer I")])
        new, changed = store.diff([_job(title="Engineer II")])
        assert new == [] and len(changed) == 1

    def test_irrelevant_field_change_not_reported_as_changed(self, store):
        store.diff([_job(salary_range="100k")])
        new, changed = store.diff([_job(salary_range="200k")])
        assert changed == []  # content_hash excludes salary_range

    def test_duplicate_key_within_same_batch(self, store):
        # two jobs with identical key in one call — must not crash/double count
        new, changed = store.diff([_job(), _job()])
        assert store.count() == 1


class TestMeta:
    def test_get_missing_key_is_none(self, store):
        assert store.get_meta("last_scan") is None

    def test_set_then_get(self, store):
        store.set_meta("last_scan", "2026-01-01T00:00:00+00:00")
        assert store.get_meta("last_scan") == "2026-01-01T00:00:00+00:00"

    def test_set_overwrites(self, store):
        store.set_meta("k", "v1")
        store.set_meta("k", "v2")
        assert store.get_meta("k") == "v2"


class TestAddedSince:
    def test_strictly_after_excludes_boundary(self, store):
        store.diff([_job()])
        row = store.conn.execute("SELECT first_seen FROM jobs").fetchone()
        assert store.added_since(row["first_seen"]) == []

    def test_migration_adds_salary_range_to_legacy_db(self, tmp_path):
        import sqlite3
        path = tmp_path / "legacy.db"
        conn = sqlite3.connect(path)
        conn.executescript("""
            CREATE TABLE jobs (key TEXT PRIMARY KEY, source TEXT, company TEXT,
                external_id TEXT, title TEXT, url TEXT, location TEXT,
                department TEXT, employment_type TEXT, posted_at TEXT,
                content_hash TEXT, first_seen TEXT, last_seen TEXT);
        """)
        conn.commit(); conn.close()
        with Store(path) as s:
            cols = {r["name"] for r in s.conn.execute("PRAGMA table_info(jobs)")}
            assert "salary_range" in cols
