import os
import httpx, pytest, respx
from notify import (_line, _sms_body, notify_console, notify_slack,
                     notify_webhook, notify_sms, dispatch)
from models import Job


def _job(**kw):
    return Job(source="s", company="acme", external_id="1", title="Eng",
               url="http://x", **kw)


class TestSmsBody:
    def test_truncates_at_limit_with_more_count(self):
        jobs = [_job(title=f"Job {i}") for i in range(10)]
        body = _sms_body(jobs, [], limit=8)
        assert "+2 more" in body
        assert body.count("Job") == 8  # only 8 line items rendered

    def test_ascii_only_no_bullets(self):
        assert "\u2022" not in _sms_body([_job()], [])


class TestEnvGatedNotifiers:
    def test_slack_noop_without_env_var(self, monkeypatch):
        monkeypatch.delenv("SLACK_WEBHOOK_URL", raising=False)
        notify_slack([_job()], [])  # must not raise / must not attempt network

    @respx.mock
    def test_slack_noop_with_no_jobs_even_if_configured(self, monkeypatch):
        monkeypatch.setenv("SLACK_WEBHOOK_URL", "https://hooks.slack.test/x")
        route = respx.post("https://hooks.slack.test/x")
        notify_slack([], [])
        assert route.call_count == 0

    @respx.mock
    def test_slack_posts_when_configured_and_jobs_present(self, monkeypatch):
        monkeypatch.setenv("SLACK_WEBHOOK_URL", "https://hooks.slack.test/x")
        route = respx.post("https://hooks.slack.test/x").mock(
            return_value=httpx.Response(200))
        notify_slack([_job()], [])
        assert route.call_count == 1

    def test_sms_requires_all_four_env_vars(self, monkeypatch):
        monkeypatch.setenv("TWILIO_ACCOUNT_SID", "sid")
        monkeypatch.delenv("TWILIO_AUTH_TOKEN", raising=False)
        notify_sms([_job()], [])  # missing token -> no-op, no network attempt


class TestDispatch:
    def test_one_notifier_failure_does_not_block_others(self, monkeypatch, capsys):
        calls = []
        def good(new, changed): calls.append("good")
        def bad(new, changed): raise RuntimeError("boom")
        monkeypatch.setattr("notify.NOTIFIERS", [bad, good])
        dispatch([_job()], [])
        assert calls == ["good"]
        assert "notifier bad failed" in capsys.readouterr().out
